@app.route("/cache/clear", methods=["POST"])
def clear_cache():
    deleted = 0
    try:
        cursor = 0
        pattern = f"{CACHE_PREFIX}*"
        while True:
            cursor, keys = redis_client.scan(cursor=cursor, match=pattern, count=500)
            if keys:
                deleted += redis_client.delete(*keys)
            if cursor == 0:
                break
    except redis.RedisError:
        return jsonify({"error": "cache clear failed"}), 500

    return jsonify({"status": "ok", "deleted": deleted})


@app.route("/health")
def health():
    try:
        pong = redis_client.ping()
        return jsonify({"status": "ok", "redis": bool(pong)})
    except redis.RedisError as exc:
        return jsonify({"status": "degraded", "redis": False, "error": str(exc)}), 503


